import sky
import json
import traceback

def main():
    result = {
        "task_name": "sdk-echo-task",
        "cluster_name": "sky-bench-sdk"
    }

    try:
        task = sky.Task(
            name="sdk-echo-task",
            run="echo 'hello from skypilot sdk'"
        )
        task.set_resources(sky.Resources(
            cloud=sky.GCP(),
            instance_type="n1-standard-1",
            region="us-central1"
        ))

        request_id = sky.launch(task, cluster_name="sky-bench-sdk")

        if request_id is not None:
            job_id, handle = sky.stream_and_get(request_id)

        result["status"] = "launched"
    except Exception as e:
        result["status"] = "error"
        result["error"] = str(e)

    with open("/home/user/launch_result.json", "w") as f:
        json.dump(result, f, indent=2)

if __name__ == "__main__":
    main()

